import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        int initial = countComponents(n, edges, -1);
        if (initial >= k) {
            return 0;
        }

        long maxTime = 0;
        for (long[] edge : edges) {
            if (edge[2] > maxTime) {
                maxTime = edge[2];
            }
        }

        long low = 0;
        long high = maxTime;
        long answer = maxTime;

        while (low <= high) {
            long mid = (low + high) / 2;
            int current = countComponents(n, edges, mid);
            if (current >= k) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return answer;
    }

    private static int countComponents(long n, long[][] edges, long t) {
        List<List<Long>> adj = new ArrayList<>();
        for (long i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }

        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long time = edge[2];
            if (time > t) {
                adj.get((int) u).add(v);
                adj.get((int) v).add(u);
            }
        }

        boolean[] visited = new boolean[(int) n];
        int count = 0;

        for (long i = 0; i < n; i++) {
            if (!visited[i]) {
                count++;
                Queue<Long> queue = new LinkedList<>();
                queue.add(i);
                visited[i] = true;

                while (!queue.isEmpty()) {
                    long node = queue.poll();
                    for (long neighbor : adj.get((int) node)) {
                        if (!visited[neighbor]) {
                            visited[neighbor] = true;
                            queue.add(neighbor);
                        }
                    }
                }
            }
        }

        return count;
    }
}
