import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        long initialComponents = countComponents(n, edges, -1);
        if (initialComponents >= k) {
            return 0;
        }
        long maxTime = 0;
        for (long[] edge : edges) {
            if (edge[2] > maxTime) {
                maxTime = edge[2];
            }
        }
        long low = 0;
        long high = maxTime;
        long answer = maxTime;
        while (low <= high) {
            long mid = (low + high) / 2;
            long current = countComponents(n, edges, mid);
            if (current >= k) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return answer;
    }

    private static long countComponents(long n, long[][] edges, long t) {
        List<List<Long>> adj = new ArrayList<>();
        for (long i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long time = edge[2];
            if (time > t) {
                adj.get((int) u).add(v);
                adj.get((int) v).add(u);
            }
        }
        boolean[] visited = new boolean[(int) n];
        long count = 0;
